// Sauvegarde le media reçu dans le staticData (persistant entre exécutions)
const staticData = $getWorkflowStaticData('global');
const msg = $input.first().json.message;
const chatId = String(msg.chat.id);

const fileId = msg.video
  ? msg.video.file_id
  : msg.photo.slice(-1)[0].file_id;

const mediaType = msg.video ? 'video' : 'photo';

staticData[`pending_${chatId}`] = {
  fileId,
  mediaType,
  timestamp: Date.now()
};

return [{ json: { chatId, fileId, mediaType } }];

// Charge le media sauvegardé et extrait le style choisi
const staticData = $getWorkflowStaticData('global');
const msg = $input.first().json.message;
const chatId = String(msg.chat.id);
const text = msg.text || '';

// Map bouton → style interne
const styleMap = {
  'Scandinave': 'scandinavian',
  'Industriel': 'industrial',
  'Moderne': 'modern_minimalist',
  'Classique': 'classic_french',
  'Bohème': 'bohemian'
};

let chosenStyle = 'modern_minimalist';
let chosenLabel = 'Moderne';
for (const [label, value] of Object.entries(styleMap)) {
  if (text.includes(label)) {
    chosenStyle = value;
    chosenLabel = label;
    break;
  }
}

const pending = staticData[`pending_${chatId}`];
if (!pending) {
  return [{ json: { chatId, fileId: '', mediaType: '', chosenStyle, chosenLabel, error: true } }];
}

const result = {
  chatId,
  fileId: pending.fileId,
  mediaType: pending.mediaType,
  chosenStyle,
  chosenLabel,
  error: false
};

// Nettoyage
delete staticData[`pending_${chatId}`];

return [{ json: result }];

// Build file URL from Telegram getFile API response
const input = $input.first().json;
const mediaType = $('Load Media + Style').first().json.mediaType;

// HTTP Request returns { ok, result: { file_path } }
const filePath = input.result?.file_path || input.file_path || '';
const botToken = '8120972729:AAFlDrC7dfgnTAqAjlc4pUsadqxjhc5IYOU';
const fileUrl = filePath.startsWith('http') ? filePath : `https://api.telegram.org/file/bot${botToken}/${filePath}`;

return [{ json: { frameUrl: fileUrl, lastFrameUrl: fileUrl, mediaType, fileUrl } }];

// Auto-Upsell : génère un message contextuel basé sur l'analyse
const analysis = JSON.parse($input.first().json.choices[0].message.content);
const chatId = $('Load Media + Style').first().json.chatId;
const chosenLabel = $('Load Media + Style').first().json.chosenLabel;

const roomLabels = {
  living_room: 'salon', bedroom: 'chambre', kitchen: 'cuisine',
  bathroom: 'salle de bain', dining_room: 'salle à manger',
  office: 'bureau', studio: 'studio'
};

const suggestions = {
  living_room: 'ajouter un éclairage d\'ambiance tamisé et une disposition de canapé qui maximise la perception d\'espace',
  bedroom: 'intégrer du textile chaleureux et un éclairage cocooning pour créer une atmosphère intime',
  kitchen: 'ajouter des accessoires de cuisine haut de gamme et un plan de travail épuré',
  bathroom: 'intégrer des plantes vertes et un éclairage spa pour une ambiance zen',
  dining_room: 'ajouter un luminaire suspendu comme point focal et un set de table élégant',
  office: 'intégrer un setup ergonomique avec des étagères décoratives',
  studio: 'optimiser chaque zone avec du mobilier multifonction'
};

const roomType = analysis.roomType || 'living_room';
const roomLabel = roomLabels[roomType] || 'pièce';
const suggestion = suggestions[roomType] || suggestions.living_room;
const lightInfo = analysis.lighting?.naturalLight || 'modérée';
const area = analysis.dimensions?.estimatedArea || '';

let upsell = `🔍 *Analyse terminée !*\n\n`;
upsell += `J'ai détecté un(e) *${roomLabel}*`;
if (area) upsell += ` d'environ *${area}*`;
upsell += ` avec une luminosité *${lightInfo}*.\n\n`;
upsell += `💡 En style *${chosenLabel}*, je vais ${suggestion}.\n\n`;
upsell += `_(Option incluse dans votre rendu)_\n\n`;
upsell += `⏳ Génération des 5 étapes de transformation en cours...`;

return [{ json: { chatId, upsellText: upsell, analysis } }];

