const promptsData = JSON.parse($input.first().json.choices[0].message.content);
const frames = promptsData.frames;
const controlnet = promptsData.controlnet;

return frames.map(frame => ({
  json: {
    ...frame,
    negativePrompt: promptsData.negativePrompt,
    controlnetStrength: controlnet.strength,
    guidanceScale: controlnet.guidanceScale,
    model: controlnet.model
  }
}));

const items = $input.all();
const images = items.map((item, i) => ({
  url: item.json.output[0],
  step: i + 1,
  label: ['original_clean','surface_renovation','large_furniture','full_furnishing','final_decoration'][i]
}));

return [{ json: { images } }];

const chatId = $('Load Media + Style').first().json.chatId;
const chosenStyle = $('Load Media + Style').first().json.chosenStyle;
const images = $('Aggregate 5 Images').first().json.images;
const aiVideoUrl = $input.first().json.video_url;
const roomAnalysis = JSON.parse($('Agent IA — Vision Analysis').first().json.choices[0].message.content);

const remotionPayload = {
  originalVideoUrl: $('Download Media').first().json.fileUrl,
  aiVideoUrl: aiVideoUrl,
  images: images,
  metadata: {
    roomAnalysis: roomAnalysis,
    chosenStyle: chosenStyle,
    generationConfig: {
      model: 'stability-ai/sdxl',
      controlnetModel: 'canny',
      controlnetStrength: 0.85,
      guidanceScale: 7.5,
      promptStrength: 0.6,
      negativePrompt: 'blurry, distorted, deformed, low quality, watermark, text, unrealistic proportions, floating furniture, mismatched perspective, cartoon, anime, illustration',
      width: 1344,
      height: 768,
      baseSeed: 42
    }
  },
  videoConfig: {
    fps: 30,
    durationInSeconds: 10,
    width: 1920,
    height: 1080,
    speedRamp: {
      introSpeed: 2.0,
      stagingSpeed: 0.5,
      outroSpeed: 2.0,
      introRatio: 0.2,
      stagingRatio: 0.6,
      outroRatio: 0.2
    },
    transitions: { durationInFrames: 16, smoothCutBlur: 4 },
    upscaling: { enabled: true, contrast: 1.1, saturation: 1.05 }
  },
  telegram: { chatId: chatId }
};

return [{ json: remotionPayload }];
